const data = $('Combine All Data').first().json;
const templateFile = $input.first();

function generateContactLine(info) {
  if (!info) return '';
  const parts = [];
  if (info.location) parts.push(info.location);
  if (info.phone) parts.push(info.phone);
  if (info.email) parts.push(`<a href="mailto:${info.email}">${info.email}</a>`);
  if (info.linkedin) parts.push(`<a href="${info.linkedin}">LinkedIn</a>`);
  if (info.github) parts.push(`<a href="${info.github}">GitHub</a>`);
  return parts.join(' | ');
}

function generateSkillsSection(skillsByCategory) {
  if (!skillsByCategory || typeof skillsByCategory !== 'object') {
    return '<p>No skills data available.</p>';
  }
  let html = '';
  for (const [category, skills] of Object.entries(skillsByCategory)) {
    if (Array.isArray(skills) && skills.length > 0) {
      html += `<p class="skills-line"><span class="skills-label">${category}:</span> ${skills.join(', ')}</p>\n`;
    }
  }
  return html || '<p>No skills data available.</p>';
}

function generateProjectsSection(projects) {
  if (!Array.isArray(projects) || projects.length === 0) {
    return '<p>No matching projects found.</p>';
  }
  return projects.map(project => {
    if (!project) return '';
    const title = project.project_title || project.original_name || 'Untitled Project';
    const date = project.project_date || '';
    const url = project.project_url || '';
    const bullets = Array.isArray(project.impact_sentences) 
      ? project.impact_sentences.map(s => `<li>${s}</li>`).join('\n')
      : '';
    const dateSpan = date ? `<span class="entry-date">${date}</span>` : '';
    const titleHtml = url ? `<a href="${url}" class="entry-title" target="_blank">${title}</a>` : `<span class="entry-title">${title}</span>`;
    return `<div class="entry">\n<div class="entry-header">\n${titleHtml}\n${dateSpan}\n</div>\n<ul>\n${bullets}\n</ul>\n</div>`;
  }).filter(Boolean).join('\n');
}

let template = '';
try {
  const binaryDataBuffer = await this.helpers.getBinaryDataBuffer(0, 'data');
  template = binaryDataBuffer.toString('utf-8');
} catch (e) {
  throw new Error('Failed to read template file: ' + e.message);
}

if (!template || template.trim().length === 0) {
  throw new Error('Template file is empty');
}

const replacements = {
  '{{NAME}}': data.personalInfo?.name || 'Your Name',
  '{{CONTACT_LINE}}': generateContactLine(data.personalInfo),
  '{{MASTER_COURSES}}': Array.isArray(data.masterCourses) && data.masterCourses.length > 0 ? data.masterCourses.join('; ') : 'N/A',
  '{{BACHELOR_COURSES}}': Array.isArray(data.bachelorCourses) && data.bachelorCourses.length > 0 ? data.bachelorCourses.join('; ') : 'N/A',
  '{{PROJECTS_SECTION}}': generateProjectsSection(data.matchedProjects),
  '{{SKILLS_SECTION}}': generateSkillsSection(data.skillsByCategory)
};

let html = template;
for (const [placeholder, value] of Object.entries(replacements)) {
  html = html.replace(new RegExp(placeholder.replace(/[{}]/g, '\\$&'), 'g'), value);
}

const fileName = (data.personalInfo?.name || 'Resume').replace(/[^a-zA-Z0-9]/g, '_');

return [{
  json: {
    ...data,
    resumeHtml: html,
    fileName: fileName
  },
  binary: {
    resume: await this.helpers.prepareBinaryData(
      Buffer.from(html, 'utf-8'),
      `${fileName}_Resume.html`,
      'text/html; charset=utf-8'
    )
  }
}];

const items = $input.all();

const PERSONAL_INFO = {
  name: 'Your Name',
  email: 'sam.guan@example.com',
  phone: '(123) 456-7890',
  linkedin: 'https://linkedin.com/in/samguan',
  github: 'https://github.com/samguan',
  location: 'San Francisco, CA'
};

let masterCourses = [];
let bachelorCourses = [];
let skillsByCategory = {};
let projectsWithImpact = [];
let unmatchedSkills = [];

for (const item of items) {
  const data = item.json;
  if (data.masterCourses) masterCourses = data.masterCourses;
  if (data.bachelorCourses) bachelorCourses = data.bachelorCourses;
  if (data.skillsByCategory) skillsByCategory = data.skillsByCategory;
  if (data.projectsWithImpact) projectsWithImpact = data.projectsWithImpact;
  if (data.unmatchedSkills) unmatchedSkills = data.unmatchedSkills;
}

// Include JD analysis for downstream use by Cover Letter Generator
const jdAnalysisData = $('Parse JD Analysis').first().json;

return [{
  json: {
    personalInfo: PERSONAL_INFO,
    masterCourses: masterCourses,
    bachelorCourses: bachelorCourses,
    skillsByCategory: skillsByCategory,
    matchedProjects: projectsWithImpact,
    unmatchedSkills: unmatchedSkills,
    jdAnalysis: jdAnalysisData.jdAnalysis || {},
    jobDescription: jdAnalysisData.jobDescription || ''
  }
}];

const previousData = $('Parse JD Analysis').first().json;
const items = $input.all();

let projectsContent = '';
const projectsMap = {};
const projectUrlsMap = {};
const debugInfo = [];

try {
  for (let i = 0; i < items.length; i++) {
    const item = items[i];
    try {
      const binaryDataBuffer = await this.helpers.getBinaryDataBuffer(i, 'data');
      const content = binaryDataBuffer.toString('utf-8');

      const fileName = item.binary?.data?.fileName || '';
      const cleanName = fileName.replace(/\.md$/i, '').replace(/^.*[\\\/]/, '');

      const urlMatch = content.match(/^URL:\s*(.+)$/m);
      const projectUrl = urlMatch ? urlMatch[1].trim() : '';

      projectsContent += `[FILE: ${cleanName}]\n${content}\n\n`;

      debugInfo.push({
        originalFileName: fileName,
        cleanName: cleanName,
        contentLength: content.length,
        firstLine: content.split('\n')[0],
        secondLine: content.split('\n')[1] || 'NO SECOND LINE'
      });

      if (cleanName) {
        projectsMap[cleanName] = content;
        projectUrlsMap[cleanName] = projectUrl;
      }
    } catch (e) {
      debugInfo.push({ error: e.message, index: i });
    }
  }
} catch (error) {
  projectsContent = '';
}

return [{
  json: {
    ...previousData,
    projectsContent: projectsContent,
    projectsMap: projectsMap,
    projectUrlsMap: projectUrlsMap,
    branch: 'projects',
    debugProcessProjects: {
      filesProcessed: debugInfo,
      mapKeys: Object.keys(projectsMap),
      totalFiles: items.length
    }
  }
}];

const input = $input.first().json;

// Final output - extract skillsByCategory from skillsData
return [{
  json: {
    skillsByCategory: input.skillsData?.skills_by_category || {},
    branch: 'skills'
  }
}];

