const input = $input.first().json;
let skillsData = input.skillsData;

// If coming from AI - Shorten Skills Lines, parse the response
if (input.output || input.text) {
  const content = input.output || input.text || '';
  let jsonStr = content;

  if (content.includes('```json')) {
    const match = content.match(/```json\s*([\s\S]*?)\s*```/);
    if (match) jsonStr = match[1];
  } else if (content.includes('```')) {
    const match = content.match(/```\s*([\s\S]*?)\s*```/);
    if (match) jsonStr = match[1];
  } else {
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) jsonStr = jsonMatch[0];
  }

  try {
    skillsData = JSON.parse(jsonStr.trim());
  } catch (e) {
    // Keep existing skillsData if parse fails
  }
}

const MAX_CHARS = 86;
const iteration = (input.iteration || 0) + 1;

// ========== Code-based pre-trimming (first iteration only) ==========
const abbr = { 'PostgreSQL': 'Postgres', 'JavaScript': 'JS', 'TypeScript': 'TS' };
const catShort = {
  'Data Analysis & Programming': 'Programming',
  'Analytics Tools & Platforms': 'Analytics',
  'Machine Learning & AI': 'ML & AI',
  'Database Management': 'Databases',
  'Cloud & Infrastructure': 'Cloud',
  'Data Engineering & Processing': 'Data Engineering',
};

function lineLen(cat, skills) { return `${cat}: ${skills.join(', ')}`.length; }
function rmParens(s) { return s.replace(/\s*\([^)]*\)/g, '').trim(); }
function doAbbr(s) { let r = s; for (const [f, a] of Object.entries(abbr)) r = r.replace(f, a); return r; }

if (iteration === 1) {
  const refined = {};
  for (const [origCat, origSkills] of Object.entries(skillsData.skills_by_category || {})) {
    if (!Array.isArray(origSkills)) continue;
    let cat = origCat;
    let skills = [...origSkills];

    if (lineLen(cat, skills) > MAX_CHARS) {
      skills = skills.map(rmParens);
      if (lineLen(cat, skills) > MAX_CHARS) cat = catShort[cat] || cat;
      if (lineLen(cat, skills) > MAX_CHARS) skills = skills.map(doAbbr);
      while (skills.length > 3 && lineLen(cat, skills) > MAX_CHARS) skills.pop();
    }
    refined[cat] = skills;
  }
  skillsData = { skills_by_category: refined };
}

// ========== Validation ==========
function getRenderedLineLength(category, skills) {
  return `${category}: ${skills.join(', ')}`.length;
}

const skillsByCategory = skillsData.skills_by_category || {};
const tooLongCategories = [];
const validCategories = {};

for (const [category, skills] of Object.entries(skillsByCategory)) {
  if (!Array.isArray(skills)) continue;

  const lineLength = getRenderedLineLength(category, skills);
  if (lineLength > MAX_CHARS) {
    tooLongCategories.push({
      category: category,
      skills: skills,
      currentChars: lineLength,
      needToRemove: lineLength - MAX_CHARS
    });
  } else {
    validCategories[category] = skills;
  }
}

const allValid = tooLongCategories.length === 0;
const maxIterations = 5;
const shouldContinue = !allValid && iteration < maxIterations;

return [{
  json: {
    skillsData: skillsData,
    tooLongCategories: tooLongCategories,
    validCategories: validCategories,
    allValid: allValid,
    iteration: iteration,
    shouldContinue: shouldContinue,
    branch: 'skills'
  }
}];

