const input = $input.first().json;
const rawSkillsByCategory = input.rawSkillsByCategory || {};
const MAX_CHARS = 86;

const abbreviations = {
  'PostgreSQL': 'Postgres', 'JavaScript': 'JS', 'TypeScript': 'TS',
  'development': 'dev', 'Management': 'Mgmt', 'management': 'mgmt',
};

const categoryShortnames = {
  'Data Analysis & Programming': 'Programming',
  'Analytics Tools & Platforms': 'Analytics',
  'Machine Learning & AI': 'ML & AI',
  'Database Management': 'Databases',
  'Cloud & Infrastructure': 'Cloud',
  'Data Engineering & Processing': 'Data Engineering',
};

function removeParentheticals(skill) {
  return skill.replace(/\s*\([^)]*\)/g, '').trim();
}

function abbreviate(skill) {
  let result = skill;
  for (const [full, abbr] of Object.entries(abbreviations)) {
    result = result.replace(full, abbr);
  }
  return result;
}

function getLineLength(category, skills) {
  return `${category}: ${skills.join(', ')}`.length;
}

const refinedSkills = {};

for (const [category, skills] of Object.entries(rawSkillsByCategory)) {
  if (!Array.isArray(skills)) continue;

  let currentCategory = category;
  let currentSkills = [...skills];

  // Step 1: Check if already valid
  if (getLineLength(currentCategory, currentSkills) <= MAX_CHARS) {
    refinedSkills[currentCategory] = currentSkills;
    continue;
  }

  // Step 2: Remove parentheticals
  currentSkills = currentSkills.map(removeParentheticals);
  if (getLineLength(currentCategory, currentSkills) <= MAX_CHARS) {
    refinedSkills[currentCategory] = currentSkills;
    continue;
  }

  // Step 3: Shorten category name
  currentCategory = categoryShortnames[currentCategory] || currentCategory;
  if (getLineLength(currentCategory, currentSkills) <= MAX_CHARS) {
    refinedSkills[currentCategory] = currentSkills;
    continue;
  }

  // Step 4: Abbreviate skills
  currentSkills = currentSkills.map(abbreviate);
  if (getLineLength(currentCategory, currentSkills) <= MAX_CHARS) {
    refinedSkills[currentCategory] = currentSkills;
    continue;
  }

  // Step 5: Truncate to fit
  while (currentSkills.length > 3 && getLineLength(currentCategory, currentSkills) > MAX_CHARS) {
    currentSkills.pop();
  }

  refinedSkills[currentCategory] = currentSkills;
}

return [{
  json: {
    skillsData: { skills_by_category: refinedSkills },
    branch: 'skills'
  }
}];

const response = $input.item.json;
const content = response.output || response.text || '';

if (!content || content.trim() === '') {
  throw new Error('[Parse Written Impact] AI returned empty content');
}

let jsonStr = content;
if (content.includes('```json')) {
  const match = content.match(/```json\s*([\s\S]*?)\s*```/);
  if (match) jsonStr = match[1];
} else if (content.includes('```')) {
  const match = content.match(/```\s*([\s\S]*?)\s*```/);
  if (match) jsonStr = match[1];
} else {
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) jsonStr = jsonMatch[0];
}

let parsed;
try {
  parsed = JSON.parse(jsonStr.trim());
} catch (e) {
  throw new Error('[Parse Written Impact] JSON parse failed: ' + e.message);
}

if (!parsed.impact_sentences || parsed.impact_sentences.length < 4) {
  throw new Error('[Parse Written Impact] Missing or incomplete impact_sentences');
}

// Assemble full projectData from upstream context + AI bullets
const routeData = $('Route Projects').item.json;

return {
  json: {
    projectData: {
      project_title: routeData.projectTitle || '',
      project_date: routeData.projectDate || '',
      original_name: routeData.projectFileName || '',
      matched_skill: routeData.currentProject?.matched_skills || [],
      project_url: routeData.projectUrl || '',
      impact_sentences: parsed.impact_sentences,
      qa_log: parsed.qa_log || []
    },
    iteration: 0,
    branch: 'projects'
  }
};

const input = $input.item.json;

const staticData = $getWorkflowStaticData('global');
if (!staticData.projectResults) {
  staticData.projectResults = [];
}

// Guard against cross-execution contamination:
// If this item's batchId doesn't match staticData's batchId, clear stale data
const itemBatchId = input.batchId || '';
if (staticData.batchId && itemBatchId && staticData.batchId !== itemBatchId) {
  staticData.projectResults = [];
  staticData.batchId = itemBatchId;
}

if (input.projectData) {
  // Recover project_url if it was lost during AI sentence shortening
  const projectUrlsMap = $('Process Projects').first().json.projectUrlsMap || {};
  const originalName = input.projectData.original_name || '';
  if (!input.projectData.project_url && projectUrlsMap[originalName]) {
    input.projectData.project_url = projectUrlsMap[originalName];
  }

  staticData.projectResults.push(input.projectData);
}

return {
  json: {
    optimizedProject: input.projectData,
    projectCount: staticData.projectResults.length,
    branch: 'projects'
  }
};

const input = $input.item.json;
let projectData = input.projectData;

if (input.output || input.text) {
  const content = input.output || input.text || '';
  let jsonStr = content;

  if (content.includes('```json')) {
    const match = content.match(/```json\s*([\s\S]*?)\s*```/);
    if (match) jsonStr = match[1];
  } else if (content.includes('```')) {
    const match = content.match(/```\s*([\s\S]*?)\s*```/);
    if (match) jsonStr = match[1];
  } else {
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) jsonStr = jsonMatch[0];
  }

  try {
    const parsed = JSON.parse(jsonStr.trim());
    if (parsed.impact_sentences) {
      projectData.impact_sentences = parsed.impact_sentences;
    }
  } catch (e) {}
}

const MAX_CHARS = 180;
const iteration = (input.iteration || 0) + 1;

const fillerPatterns = [
  /\bby leveraging\b/gi,
  /\bthrough the use of\b/gi,
  /\bin order to\b/gi,
  /\bby utilizing\b/gi,
  /\bvia the\b/gi,
];

const abbreviationMap = {
  'development': 'dev',
  'application': 'app',
  'applications': 'apps',
  'approximately': '~',
  'processing': 'proc.',
};

function codeTrim(sentence) {
  let s = sentence;
  s = s.replace(/\s*\([^)]{10,}\)/g, '');
  for (const pattern of fillerPatterns) {
    s = s.replace(pattern, '');
  }
  for (const [full, abbr] of Object.entries(abbreviationMap)) {
    s = s.replace(new RegExp(`\\b${full}\\b`, 'gi'), abbr);
  }
  s = s.replace(/\s{2,}/g, ' ').trim();
  return s;
}

const sentences = projectData.impact_sentences || [];
const tooLongSentences = [];
const validSentences = [];

for (let i = 0; i < sentences.length; i++) {
  let sentence = sentences[i];

  if (sentence.length > MAX_CHARS && iteration === 1) {
    sentence = codeTrim(sentence);
    sentences[i] = sentence;
    projectData.impact_sentences[i] = sentence;
  }

  if (sentence.length > MAX_CHARS) {
    tooLongSentences.push({
      sentence: sentence,
      currentChars: sentence.length,
      needToRemove: sentence.length - MAX_CHARS
    });
  } else {
    validSentences.push(sentence);
  }
}

const allValid = tooLongSentences.length === 0;
const maxIterations = 5;
const shouldContinue = !allValid && iteration < maxIterations;

return {
  json: {
    projectData: projectData,
    tooLongSentences: tooLongSentences,
    validSentences: validSentences,
    allValid: allValid,
    iteration: iteration,
    shouldContinue: shouldContinue,
    branch: 'projects'
  }
};

