// ── Title & Date extraction (deterministic, no AI needed) ──
function extractTitle(content) {
  const lines = content.split('\n');
  let title = '';
  for (const line of lines) {
    if (line.startsWith('# ')) {
      title = line.replace(/^#\s+/, '').replace(/^Project Name:\s*/i, '').trim();
      break;
    }
  }
  if (!title && lines.length > 0) title = lines[0].trim();
  if (title.length > 55) {
    title = title
      .replace(/\bApplication\b/g, 'App')
      .replace(/\bRecommendation\b/g, 'Rec.');
  }
  if (title.length > 55) title = title.substring(0, 52) + '...';
  return title;
}

function extractDate(content) {
  const lines = content.split('\n');
  if (lines.length >= 2) {
    const line2 = lines[1].trim();
    const m = line2.match(/^([A-Z][a-z]{2}\s+\d{4})\s*[-\u2013]\s*([A-Z][a-z]{2}\s+\d{4}|Present)$/);
    if (m) return m[1] + ' - ' + m[2];
  }
  return 'Not specified';
}

