const data = $('Combine All Data').first().json;
const templateFile = $input.first();

function generateContactLine(info) {
  if (!info) return '';
  const parts = [];
  if (info.location) parts.push(info.location);
  if (info.phone) parts.push(info.phone);
  if (info.email) parts.push(`<a href="mailto:${info.email}">${info.email}</a>`);
  if (info.linkedin) parts.push(`<a href="${info.linkedin}">LinkedIn</a>`);
  if (info.github) parts.push(`<a href="${info.github}">GitHub</a>`);
  return parts.join(' | ');
}

function generateSkillsSection(skillsByCategory) {
  if (!skillsByCategory || typeof skillsByCategory !== 'object') {
    return '<p>No skills data available.</p>';
  }
  let html = '';
  for (const [category, skills] of Object.entries(skillsByCategory)) {
    if (Array.isArray(skills) && skills.length > 0) {
      html += `<p class="skills-line"><span class="skills-label">${category}:</span> ${skills.join(', ')}</p>\n`;
    }
  }
  return html || '<p>No skills data available.</p>';
}

function generateProjectsSection(projects) {
  if (!Array.isArray(projects) || projects.length === 0) {
    return '<p>No matching projects found.</p>';
  }
  return projects.map(project => {
