function lineLen(cat, skills) { return `${cat}: ${skills.join(', ')}`.length; }
function rmParens(s) { return s.replace(/\s*\([^)]*\)/g, '').trim(); }
function doAbbr(s) { let r = s; for (const [f, a] of Object.entries(abbr)) r = r.replace(f, a); return r; }

