      skills = skills.map(rmParens);
      if (lineLen(cat, skills) > MAX_CHARS) cat = catShort[cat] || cat;
      if (lineLen(cat, skills) > MAX_CHARS) skills = skills.map(doAbbr);
      while (skills.length > 3 && lineLen(cat, skills) > MAX_CHARS) skills.pop();
