  let projectContent = projectsMap[fileName] || '';
  if (projectContent) {
    matchedKey = fileName;
  }

  if (!projectContent) {
    const normalizedFileName = fileName.toLowerCase().replace(/[\s-]/g, '_').replace(/_+/g, '_');
    for (const [key, value] of Object.entries(projectsMap)) {
      const normalizedKey = key.toLowerCase().replace(/[\s-]/g, '_').replace(/_+/g, '_');
      if (normalizedKey === normalizedFileName || key.toLowerCase() === fileName.toLowerCase()) {
        projectContent = value;
        matchedKey = key;
        break;
      }
    }
  }

  return {
    ...project,
    projectContent: projectContent,
    projectUrl: projectUrlsMap[matchedKey] || '',
    matchedKey: matchedKey
  };
