    projectContent: project.projectContent,
    projectFileName: project.file_name,
    projectTitle: extractTitle(project.projectContent || ''),
    projectDate: extractDate(project.projectContent || ''),
    projectUrl: project.projectUrl || '',
    expectedProjectCount: enrichedProjects.length,
    batchId: batchId,
    branch: 'projects',
    projectIndex: i,
    debug: {
      availableKeys: availableKeys,
      requestedFileName: project.file_name,
      matchedKey: project.matchedKey,
      contentFound: !!project.projectContent,
